powershell -Command "
# SMB 공유 접근 시도 (관리자 공유 c$)
\$targets = @('192.168.0.202','192.168.0.203','192.168.0.207')
foreach (\$ip in \$targets) {
    \$path = \"\\\\\\\\$ip\\\\c\$\"
    try {
        \$result = Test-Path \$path -ErrorAction Stop
        Write-Host \"[\$ip] c$ 접근: \$result\"
    } catch {
        Write-Host \"[\$ip] c$ 접근 실패: \$(\$_.Exception.Message)\"
    }
}
" 2>&1

powershell -Command "
# 포트 445(SMB) 연결 가능 여부 확인
\$targets = @('192.168.0.202','192.168.0.203','192.168.0.207')
foreach (\$ip in \$targets) {
    try {
        \$tcp = New-Object System.Net.Sockets.TcpClient
        \$ar = \$tcp.BeginConnect(\$ip, 445, \$null, \$null)
        \$ok = \$ar.AsyncWaitHandle.WaitOne(2000, \$false)
        if (\$ok) { Write-Host \"[\$ip] 포트445 열림\" }
        else { Write-Host \"[\$ip] 포트445 닫힘/타임아웃\" }
        \$tcp.Close()
    } catch { Write-Host \"[\$ip] 연결 오류: \$(\$_.Exception.Message)\" }
}
" 2>&1
